// tsconfig.json üçün nümunə: {"strict": true}

// 1. strictNullChecks
// strictNullChecks aktiv olduqda null və undefined açıq şəkildə idarə olunmalıdır
let username: string | null = "Alice";
// let invalid: string = null; // Səhv: null string tipinə uyğun deyil
if (username !== null) {
  console.log(username.toUpperCase()); // Çıxış: ALICE
}

// 2. noImplicitAny
// noImplicitAny aktiv olduqda tipi açıq şəkildə müəyyən edilməlidir
function greet(name: string) {
  return "Hello, " + name;
}
// function badGreet(name) { // Səhv: name parametri any tipindədir
//   return "Hello, " + name;
// }
console.log(greet("Bob")); // Çıxış: Hello, Bob

// 3. strictBindCallApply
// strictBindCallApply aktiv olduqda bind/call/apply düzgün tiplərlə çağırılır
function add(a: number, b: number): number {
  return a + b;
}
const boundAdd = add.bind(null, 5);
console.log(boundAdd(3)); // Çıxış: 8
// console.log(add.call(null, "5", 3)); // Səhv: string tipi number gözlənilir

// 4. noImplicitThis
// noImplicitThis aktiv olduqda this tipi açıq şəkildə müəyyən edilməlidir
class User {
  name: string = "Alice";
  greet(this: User) {
    return "Hello, " + this.name;
  }
}
const user = new User();
console.log(user.greet()); // Çıxış: Hello, Alice
// function badThis() { // Səhv: this tipi müəyyən edilməyib
//   console.log(this.name);
// }

// 5. alwaysStrict
// alwaysStrict aktiv olduqda JavaScript-ə `"use strict";` əlavə edilir
// Bu, JavaScript-də ciddi rejimi tətbiq edir
console.log("Strict mode enabled by alwaysStrict");

// 6. strictFunctionTypes
// strictFunctionTypes funksiya tiplərinin ciddi yoxlanmasını təmin edir
interface Animal { kind: string; }
interface Dog extends Animal { bark(): void; }
function makeSound(animal: Animal) {
  console.log("Animal sound");
}
// let dogFn: (dog: Dog) => void = makeSound; // Səhv: Dog Animal-a uyğun deyil
let animalFn: (animal: Animal) => void = makeSound;
animalFn({ kind: "dog" }); // Çıxış: Animal sound

// 7. strictPropertyInitialization
// strictPropertyInitialization xüsusiyyətlərin ilkinləşdirilməsini tələb edir
class Profile {
  name!: string; // ! ilə ilkinləşdirmə tələbi aradan qaldırılır
  constructor() {
    this.name = "Alice"; // İlkinləşdirmə burada edilir
  }
}
// class BadProfile { // Səhv: name ilkinləşdirilməyib
//   name: string;
// }
const profile = new Profile();
console.log(profile.name); // Çıxış: Alice

// Mağaza sistemi
interface Product {
  id: string;
  name: string;
  price: number | null;
}

class Store {
  products: Product[] = [];

  addProduct(id: string, name: string, price: number | null): Product[] {
    if (price === null) {
      console.log("Warning: Price is null");
      return this.products;
    }
    const product: Product = { id, name, price };
    this.products = [...this.products, product];
    return this.products;
  }
}

const store = new Store();
console.log(store.addProduct("P001", "Laptop", 999)); // Çıxış: [{ id: "P001", name: "Laptop", price: 999 }]
console.log(store.addProduct("P002", "Phone", null)); // Çıxış: Warning: Price is null
// Çıxış: [{ id: "P001", name: "Laptop", price: 999 }]

