// Example for tsconfig.json: {"strict": true}

// 1. strictNullChecks
// When strictNullChecks is enabled, null and undefined must be explicitly handled
let username: string | null = "Alice";
// let invalid: string = null; // Error: null is not assignable to string
if (username !== null) {
  console.log(username.toUpperCase()); // Output: ALICE
}

// 2. noImplicitAny
// noImplicitAny prevents implicit any types
function greet(name: string) {
  return "Hello, " + name;
}
// function badGreet(name) { // Error: name implicitly has an any type
//   return "Hello, " + name;
// }
console.log(greet("Bob")); // Output: Hello, Bob

// 3. strictBindCallApply
// strictBindCallApply ensures correct type usage for bind/call/apply
function add(a: number, b: number): number {
  return a + b;
}
const boundAdd = add.bind(null, 5);
console.log(boundAdd(3)); // Output: 8
// console.log(add.call(null, "5", 3)); // Error: string is not assignable to number

// 4. noImplicitThis
// noImplicitThis requires explicit this type annotation
class User {
  name: string = "Alice";
  greet(this: User) {
    return "Hello, " + this.name;
  }
}
const user = new User();
console.log(user.greet()); // Output: Hello, Alice
// function badThis() { // Error: this implicitly has any type
//   console.log(this.name);
// }

// 5. alwaysStrict
// alwaysStrict adds "use strict"; to JavaScript output
console.log("Strict mode enabled by alwaysStrict");

// 6. strictFunctionTypes
// strictFunctionTypes enforces stricter function type checking
interface Animal { kind: string; }
interface Dog extends Animal { bark(): void; }
function makeSound(animal: Animal) {
  console.log("Animal sound");
}
// let dogFn: (dog: Dog) => void = makeSound; // Error: Dog is not assignable to Animal
let animalFn: (animal: Animal) => void = makeSound;
animalFn({ kind: "dog" }); // Output: Animal sound

// 7. strictPropertyInitialization
// strictPropertyInitialization requires property initialization
class Profile {
  name!: string; // ! bypasses initialization check
  constructor() {
    this.name = "Alice"; // Initialized here
  }
}
// class BadProfile { // Error: name not initialized
//   name: string;
// }
const profile = new Profile();
console.log(profile.name); // Output: Alice

// Store system
interface Product {
  id: string;
  name: string;
  price: number | null;
}

class Store {
  products: Product[] = [];

  addProduct(id: string, name: string, price: number | null): Product[] {
    if (price === null) {
      console.log("Warning: Price is null");
      return this.products;
    }
    const product: Product = { id, name, price };
    this.products = [...this.products, product];
    return this.products;
  }
}

const store = new Store();
console.log(store.addProduct("P001", "Laptop", 999)); // Output: [{ id: "P001", name: "Laptop", price: 999 }]
console.log(store.addProduct("P002", "Phone", null)); // Output: Warning: Price is null
// Output: [{ id: "P001", name: "Laptop", price: 999 }]

